import requests

def update_data_put(url: str, data: dict, headers: dict = None) -> dict:
    if headers is None:
        headers = {}

    try:
        response = requests.put(url, json=data, headers=headers)
        response.raise_for_status()
        return response.json()
    except requests.exceptions.HTTPError as http_err:
        return {"error": str(http_err), "details": response.text if 'response' in locals() else "No response body available"}
    except requests.exceptions.ConnectionError as conn_err:
        return {"error": str(conn_err)}
    except requests.exceptions.Timeout as timeout_err:
        return {"error": str(timeout_err)}
    except requests.exceptions.RequestException as req_err:
        return {"error": str(req_err)}
    except ValueError as json_decode_err:
        return {"error": str(json_decode_err), "details": response.text if 'response' in locals() else "No response body available"}
